class RecipeIngredientScaler{constructor(container,options={}){this.container=typeof container==='string'?document.querySelector(container):container;if(!this.container){throw new Error('RecipeIngredientScaler: Container element not found.')}this.list=this.container.querySelector('[data-ingredient-list]');this.input=this.container.querySelector('[data-portion-input]');this.decreaseBtn=this.container.querySelector('[data-action="decrease"]');this.increaseBtn=this.container.querySelector('[data-action="increase"]');this.resetBtn=this.container.querySelector('[data-action="reset"]');this.status=this.container.querySelector('[data-scaler-status]');if(!this.input){throw new Error('RecipeIngredientScaler: [data-portion-input] fehlt im Markup.')}const basePortionsAttr=this.input.dataset.basePortions;this.basePortions=parseFloat(basePortionsAttr??this.input.value??4);if(!this.basePortions||this.basePortions<=0){throw new Error('RecipeIngredientScaler: Ungültige oder fehlende data-base-portions / value am Eingabefeld.')}this.currentPortions=this.basePortions;this.minPortions=options.minPortions??parseFloat(this.input.min)??1;this.maxPortions=options.maxPortions??parseFloat(this.input.max)??99;this.step=options.step??parseFloat(this.input.step)??1;this.decimalPlaces=options.decimalPlaces??1;this.ingredients=this._collectIngredients();this._bindEvents();this._render()}_collectIngredients(){if(!this.list){return[]}return Array.from(this.list.querySelectorAll('[data-base-amount]')).map((el)=>{const baseAmount=parseFloat(el.dataset.baseAmount);if(isNaN(baseAmount)){return null}return{element:el,amountEl:el.querySelector('[data-amount]')||el,baseAmount}}).filter(Boolean)}_bindEvents(){this.decreaseBtn?.addEventListener('click',()=>this.decrease());this.increaseBtn?.addEventListener('click',()=>this.increase());this.resetBtn?.addEventListener('click',()=>this.reset());this.input.addEventListener('change',(e)=>{this.setPortions(parseFloat(e.target.value))});this.input.addEventListener('keydown',(e)=>{if(e.key==='Enter'){e.preventDefault();this.setPortions(parseFloat(e.target.value))}})}increase(){this.setPortions(this.currentPortions+this.step)}decrease(){this.setPortions(this.currentPortions-this.step)}reset(){this.setPortions(this.basePortions)}setPortions(value){if(isNaN(value)){value=this.currentPortions}value=Math.min(this.maxPortions,Math.max(this.minPortions,value));this.currentPortions=value;this._render()}_render(){this.input.value=this._formatAmount(this.currentPortions);this._scaleIngredients();this._updateButtonStates();this._announce()}_scaleIngredients(){const factor=this.currentPortions/this.basePortions;this.ingredients.forEach((ingredient)=>{const scaled=ingredient.baseAmount*factor;ingredient.amountEl.textContent=this._formatAmount(scaled)})}_formatAmount(value){const factor=Math.pow(10,this.decimalPlaces);const rounded=Math.round(value*factor)/factor;return rounded.toLocaleString('de-DE',{maximumFractionDigits:this.decimalPlaces})}_updateButtonStates(){if(this.decreaseBtn){this.decreaseBtn.disabled=this.currentPortions<=this.minPortions}if(this.increaseBtn){this.increaseBtn.disabled=this.currentPortions>=this.maxPortions}if(this.resetBtn){this.resetBtn.disabled=this.currentPortions===this.basePortions}}_announce(){if(!this.status){return}const formatted=this._formatAmount(this.currentPortions);const einheit=this.currentPortions===1?'Portion':'Portionen';this.status.textContent=`Zutaten für ${ formatted } ${ einheit } berechnet.`}}